"use client";

import { useProjects } from "@/lib/hooks/useProjects";
import { LeftPanel } from "@/components/layout/LeftPanel";
import { useState } from "react";
import { addDoc, collection, serverTimestamp } from "firebase/firestore";
import { db } from "@/lib/firebase/client";
import { useRouter } from "next/navigation";
import Link from "next/link";

export default function ProjectsPage() {
  const { projects, loading } = useProjects();
  const [creating, setCreating] = useState(false);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [busy, setBusy] = useState(false);
  const router = useRouter();

  const handleCreate = async () => {
    if (!name.trim() || busy) return;
    setBusy(true);
    try {
      const doc = await addDoc(collection(db, "pb_projects"), {
        name: name.trim(),
        description: description.trim() || null,
        createdBy: "user",
        createdAt: serverTimestamp(),
        isCore: false,
      });
      router.push(`/projects/${doc.id}/room`);
    } catch (e) {
      console.error(e);
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden text-[var(--text-blue)] bg-transparent">
      <LeftPanel />

      <div className="flex-1 flex flex-col min-w-0 px-16 py-12">
        <div className="flex items-center justify-between mb-8">
          <h1 className="text-[22px] font-semibold text-[var(--text-bright)] tracking-tight">
            Workspace
          </h1>
          <button
            onClick={() => setCreating(true)}
            className="rounded-full bg-white px-6 py-2 text-[10px] font-bold uppercase tracking-[0.3em] text-black soft-elevate hover:bg-white/90 transition-opacity"
          >
            + New Project
          </button>
        </div>

        {/* Create project modal */}
        {creating && (
          <div className="fixed inset-0 z-50 flex items-center justify-center">
            <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setCreating(false)} />
            <div className="relative z-10 w-full max-w-sm rounded-[24px] border border-white/10 bg-[var(--panel)] shadow-2xl px-7 py-6 space-y-4">
              <span className="text-[10px] font-bold tracking-[0.35em] uppercase text-[var(--text-blue)]/60">
                New Project
              </span>
              <input
                autoFocus
                type="text"
                placeholder="Project name"
                value={name}
                onChange={(e) => setName(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handleCreate()}
                className="w-full rounded-xl border border-white/10 bg-white/5 px-4 py-3 text-[14px] text-[var(--text-blue)] placeholder:text-[var(--muted)]/50 focus:outline-none focus:border-white/25"
              />
              <input
                type="text"
                placeholder="Description (optional)"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="w-full rounded-xl border border-white/10 bg-white/5 px-4 py-3 text-[13px] text-[var(--text-blue)] placeholder:text-[var(--muted)]/50 focus:outline-none focus:border-white/25"
              />
              <div className="flex gap-3 pt-1">
                <button
                  onClick={handleCreate}
                  disabled={busy || !name.trim()}
                  className="flex-1 rounded-full bg-white px-4 py-2.5 text-[10px] font-bold uppercase tracking-[0.3em] text-black disabled:opacity-40 soft-elevate"
                >
                  {busy ? "Creating…" : "Create"}
                </button>
                <button
                  onClick={() => setCreating(false)}
                  className="rounded-full border border-white/10 bg-white/5 px-4 py-2.5 text-[10px] font-bold uppercase tracking-widest text-[var(--text-blue)] hover:bg-white/10"
                >
                  Cancel
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Project grid */}
        {loading ? (
          <div className="text-[13px] text-[var(--muted)]">Loading…</div>
        ) : projects.length === 0 ? (
          <div className="text-[13px] text-[var(--muted)]">No projects yet. Create your first project above.</div>
        ) : (
          <div className="grid grid-cols-3 gap-4">
            {projects.map((p) => (
              <Link
                key={p.id}
                href={`/projects/${p.id}/room`}
                className="rounded-2xl border border-white/10 bg-black/20 p-5 hover:border-white/20 transition-colors"
              >
                <div className="flex items-start justify-between mb-2">
                  <span className="text-[15px] font-medium text-[var(--text-bright)]">{p.name}</span>
                  {p.isCore && (
                    <span className="text-[8px] font-bold tracking-widest uppercase border border-white/20 px-1.5 py-0.5 rounded text-[var(--muted)]">
                      CORE
                    </span>
                  )}
                </div>
                {p.description && (
                  <p className="text-[12px] text-[var(--muted)] line-clamp-2">{p.description}</p>
                )}
              </Link>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
