"use client";

import Link from "next/link";
import { useProjects } from "@/lib/hooks/useProjects";

interface LeftPanelProps {
  activeProjectId?: string;
}

export function LeftPanel({ activeProjectId }: LeftPanelProps) {
  const { projects, loading } = useProjects();

  return (
    <div className="w-60 border-r border-white/10 flex flex-col h-full bg-transparent">
      {/* Header */}
      <div className="px-5 pt-6 pb-4 border-b border-white/10">
        <span className="text-[10px] font-bold tracking-[0.35em] uppercase text-[var(--text-blue)]/60">
          Projects
        </span>
      </div>

      {/* Project list */}
      <div className="flex-1 overflow-y-auto custom-scrollbar py-3">
        {loading ? (
          <div className="px-5 py-2 text-[11px] text-[var(--muted)]">Loading…</div>
        ) : projects.length === 0 ? (
          <div className="px-5 py-4 text-[11px] text-[var(--muted)]">No projects yet.</div>
        ) : (
          projects.map((p) => (
            <Link
              key={p.id}
              href={`/projects/${p.id}/room`}
              className={`flex items-center gap-2 px-5 py-2.5 text-[13px] transition-colors rounded-lg mx-2 ${
                p.id === activeProjectId
                  ? "bg-white/10 text-[var(--text-bright)]"
                  : "text-[var(--text-blue)] hover:bg-white/5"
              }`}
            >
              <span className="truncate flex-1">{p.name}</span>
              {p.isCore && (
                <span className="shrink-0 text-[8px] font-bold tracking-widest uppercase border border-white/20 px-1.5 py-0.5 rounded text-[var(--muted)]">
                  CORE
                </span>
              )}
            </Link>
          ))
        )}
      </div>

      {/* Bottom links */}
      <div className="border-t border-white/10 py-3 px-2 flex flex-col gap-1">
        <Link
          href="/projects"
          className="px-3 py-2 text-[11px] text-[var(--muted)] hover:text-[var(--text-blue)] transition-colors rounded"
        >
          Workspace
        </Link>
        <Link
          href="/agents"
          className="px-3 py-2 text-[11px] text-[var(--muted)] hover:text-[var(--text-blue)] transition-colors rounded"
        >
          Agent Directory
        </Link>
      </div>
    </div>
  );
}
